mapper.select:
SELECT * FROM system_monitor 
WHERE metric_name = #{metricName} 
ORDER BY create_time DESC
LIMIT #{limit}

SELECT * FROM api_metric 
WHERE api_path = #{apiPath} 
ORDER BY create_time DESC
LIMIT #{limit}

mapper.update:
UPDATE sandbox_status 
SET status = #{status}, cpu_usage = #{cpuUsage}, memory_usage = #{memoryUsage}, update_time = NOW()
WHERE container_id = #{containerId}

mapper.select:
SELECT * FROM system_log 
ORDER BY create_time DESC
LIMIT #{size} OFFSET #{page}

SELECT * FROM system_log 
WHERE level = #{level} 
ORDER BY create_time DESC
LIMIT #{size} OFFSET #{page}

SELECT * FROM alert_record 
ORDER BY create_time DESC
LIMIT #{size} OFFSET #{page}
